${SEP}'3a static int gcd(int a, int b)
{
	while (b) { int t = b; b = a % b; a = t; }
	return a;
}

static void ex_detect_indent(struct buf *p)
{
	int n = lbuf_len(p->lb);
	int max = n < xidt ? n : xidt;
	int tab_lines = 0, space_lines = 0;
	int hist[129];
	memset(hist, 0, sizeof(hist));

	for (int i = 0; i < max; i++) {
		char *ln = lbuf_get(p->lb, i);
		if (!ln)
			continue;
		int tabs = 0, spaces = 0;
		char *s = ln;
		for (;; s++) {
			if (*s == ' ')
				spaces++;
			else if (*s == '\\t')
				tabs++;
			else
				break;
		}
		if (tabs && !spaces)
			tab_lines++;
		else if (spaces && spaces <= 128) {
			space_lines++;
			hist[spaces]++;
		}
	}
	if (tab_lines <= space_lines && space_lines > 0) {
		int g = 0;
		for (int j = 1; j <= 128; j++)
			if (hist[j])
				g = g ? gcd(g, j) : j;
		if (g < 2 || g > 8)
			g = 4;
		p->et = xet = 1;
		p->sw = xsw = g;
		p->ts = xts = g;
	} else if (tab_lines > space_lines)
		p->et = xet = 0;
}

